{"subject":"IRS","year":2000,"question":"The Hadith \"The ink of the scholar is more sacred than the blood of the martyr\" is:","options":[\"A weak or fabricated hadith\",\"A sahih hadith\",\"A Quranic verse\",\"A saying of the companions\"],"correctIndex":0,"explanation":"This is a well-known but weak/fabricated hadith."},
{"subject":"IRS","year":2001,"question":"The Hadith \"Whoever reads one letter of the Quran, he will have one good deed, and each good deed is multiplied by ten\" is from:","options":[\"Sunan al-Tirmidhi\",\"Sahih al-Bukhari\",\"Sahih Muslim\",\"Sunan Abu Dawud\"],"correctIndex":0,"explanation":"It is recorded by al-Tirmidhi."},
{"subject":"IRS","year":2002,"question":"The Hadith \"The Prophet said: \"The best of you are those who are best to their wives\"\" is from:","options":[\"Sahih al-Bukhari\",\"Sahih Muslim\",\"Sunan al-Tirmidhi\",\"Sunan Ibn Majah\"],"correctIndex":0,"explanation":"It is in Sahih al-Bukhari."},
{"subject":"IRS","year":2003,"question":"The Hadith \"The month of Ramadan is a month whose beginning is mercy, middle is forgiveness, and end is freedom from the Fire\" is:","options":[\"A well-known but weak hadith\",\"A sahih hadith\",\"A fabricated hadith\",\"A verse of the Quran\"],"correctIndex":0,"explanation":"This hadith is often quoted but its chain is weak."},
{"subject":"IRS","year":2004,"question":"The Hadith \"Whoever walks to the Friday prayer, Allah will write for him the reward of a year of fasting and prayer for every step\" is:","options":[\"A weak hadith\",\"A sahih hadith\",\"A fabricated hadith\",\"A Quranic verse\"],"correctIndex":0,"explanation":"This is not a sahih hadith."},
{"subject":"IRS","year":2005,"question":"The Hadith \"Three things are from the nature (fitrah): circumcision, clipping the nails, and trimming the moustache\" is from:","options":[\"Sahih al-Bukhari\",\"Sahih Muslim\",\"Sunan Abu Dawud\",\"Sunan Ibn Majah\"],"correctIndex":0,"explanation":"It is in Sahih al-Bukhari and Muslim."},
{"subject":"IRS","year":2006,"question":"The Hadith \"If a Muslim plants a tree and whatever is eaten from it is charity, whatever is stolen from it is charity...\" is from:","options":[\"Sahih Muslim\",\"Sahih al-Bukhari\",\"Sunan Abu Dawud\",\"Sunan al-Tirmidhi\"],"correctIndex":0,"explanation":"It is in Sahih Muslim."},
{"subject":"IRS","year":2007,"question":"The Hadith \"Whoever is not merciful to others, Allah will not be merciful to him\" is from:","options":[\"Sahih al-Bukhari\",\"Sahih Muslim\",\"Sunan al-Tirmidhi\",\"Sunan Abu Dawud\"],"correctIndex":0,"explanation":"It is in Sahih al-Bukhari."},
{"subject":"IRS","year":2008,"question":"The Hadith \"A good word is charity\" is from:","options":[\"Sahih al-Bukhari\",\"Sahih Muslim\",\"Sunan al-Tirmidhi\",\"All of these\"],"correctIndex":3,"explanation":"It is reported in multiple collections."},
{"subject":"IRS","year":2009,"question":"The Hadith \"The strong is not the one who wrestles, but the strong is the one who controls himself at the time of anger\" is from:","options":[\"Sahih al-Bukhari\",\"Sahih Muslim\",\"Sunan Abu Dawud\",\"Sunan al-Tirmidhi\"],"correctIndex":0,"explanation":"It is in Sahih al-Bukhari."},
{"subject":"IRS","year":2010,"question":"The Hadith \"Beware of jealousy, for jealousy consumes good deeds just as fire consumes wood\" is from:","options":[\"Sunan Abu Dawud\",\"Sahih al-Bukhari\",\"Sahih Muslim\",\"Sunan Ibn Majah\"],"correctIndex":0,"explanation":"It is recorded by Abu Dawud."},
{"subject":"IRS","year":2011,"question":"The Hadith \"The best of you are those who are the most beneficial to people\" is a:","options":[\"Prophetic tradition\",\"Quranic verse\",\"Fiqh principle\",\"Saying of Abu Bakr\"],"correctIndex":0,"explanation":"It is a hadith."},
{"subject":"IRS","year":2012,"question":"The Hadith \"Whoever believes in Allah and the Last Day, let him not harm his neighbour\" is from:","options":[\"Sahih al-Bukhari\",\"Sahih Muslim\",\"Sunan al-Tirmidhi\",\"All of these\"],"correctIndex":3,"explanation":"It is in multiple collections."},
{"subject":"IRS","year":2013,"question":"The Hadith \"The believer is not the one who eats his fill while his neighbour is hungry\" is from:","options":[\"Sahih al-Bukhari\",\"Sahih Muslim\",\"Sunan al-Tirmidhi\",\"Sunan Ibn Majah\"],"correctIndex":0,"explanation":"It is in Sahih al-Bukhari."},
{"subject":"IRS","year":2014,"question":"The Hadith \"The best of the Muslims is he from whose tongue and hands the Muslims are safe\" is from:","options":[\"Sahih al-Bukhari\",\"Sahih Muslim\",\"Sunan al-Tirmidhi\",\"Sunan Abu Dawud\"],"correctIndex":0,"explanation":"It is in Sahih al-Bukhari."},
{"subject":"IRS","year":2015,"question":"The Hadith \"The prayer of a person in congregation is multiplied by 27 times more than his prayer alone\" is from:","options":[\"Sahih al-Bukhari\",\"Sahih Muslim\",\"Sunan Abu Dawud\",\"All of these\"],"correctIndex":3,"explanation":"It is reported in multiple collections."},
{"subject":"IRS","year":2016,"question":"The Hadith \"Whoever performs wudu perfectly, his sins will exit from his body until they exit from under his nails\" is from:","options":[\"Sahih Muslim\",\"Sahih al-Bukhari\",\"Sunan Abu Dawud\",\"Sunan al-Tirmidhi\"],"correctIndex":0,"explanation":"It is in Sahih Muslim."},
