// ============================================================
// SECTION 3: PILLARS OF ISLAM – IMAN, SALAT, ZAKAT, SAWM, HAJJ (Q281–Q420)
// ============================================================
{"subject":"IRS","year":2000,"question":"The five pillars of Islam are:","options":[\"Shahadah, Salah, Zakat, Sawm, Hajj\",\"Shahadah, Salah, Zakat, Sawm, Jihad\",\"Shahadah, Salah, Zakat, Hajj, Umrah\",\"Shahadah, Salah, Zakat, Sawm, Ihsan\"],"correctIndex":0,"explanation":"These are the five pillars."},
{"subject":"IRS","year":2001,"question":"The testimony of faith (Shahadah) is:","options":[\"\"La ilaha illallah, Muhammadur Rasulullah\"\",\"\"Allahu Akbar\"\",\"\"Subhanallah\"\",\"\"Alhamdulillah\"\"],"correctIndex":0,"explanation":"The Shahadah is the declaration of faith."},
{"subject":"IRS","year":2002,"question":"The five daily prayers are:","options":[\"Fajr, Dhuhr, Asr, Maghrib, Isha\",\"Fajr, Dhuhr, Asr, Maghrib, Witr\",\"Fajr, Dhuhr, Asr, Maghrib, Tahajjud\",\"Dhuhr, Asr, Maghrib, Isha, Witr\"],"correctIndex":0,"explanation":"These are the five obligatory daily prayers."},
{"subject":"IRS","year":2003,"question":"The number of rak\"ahs in Fajr prayer is:","options":[\"2\",\"3\",\"4\",\"1\"],"correctIndex":0,"explanation":"Fajr has 2 rak\"ahs sunnah (mu\"akkadah) and 2 fard, but the fard is 2."},
{"subject":"IRS","year":2004,"question":"The number of rak\"ahs in Dhuhr prayer is:","options":[\"4 fard (plus sunnah)\",\"3\",\"2\",\"5\"],"correctIndex":0,"explanation":"Dhuhr has 4 fard rak\"ahs."},
{"subject":"IRS","year":2005,"question":"The number of rak\"ahs in Asr prayer is:","options":[\"4\",\"3\",\"2\",\"1\"],"correctIndex":0,"explanation":"Asr has 4 fard rak\"ahs."},
{"subject":"IRS","year":2006,"question":"The number of rak\"ahs in Maghrib prayer is:","options":[\"3\",\"4\",\"2\",\"5\"],"correctIndex":0,"explanation":"Maghrib has 3 fard rak\"ahs."},
{"subject":"IRS","year":2007,"question":"The number of rak\"ahs in Isha prayer is:","options":[\"4\",\"3\",\"2\",\"5\"],"correctIndex":0,"explanation":"Isha has 4 fard rak\"ahs."},
{"subject":"IRS","year":2008,"question":"Zakat is obligatory on:","options":[\"Wealth exceeding the Nisab (minimum threshold)\",\"All income\",\"Land only\",\"Houses only\"],"correctIndex":0,"explanation":"Zakat is due on wealth above the Nisab."},
{"subject":"IRS","year":2009,"question":"The Nisab (minimum threshold) for gold is:","options":[\"85 grams\",\"20 grams\",\"50 grams\",\"100 grams\"],"correctIndex":0,"explanation":"85 grams of gold is the Nisab."},
{"subject":"IRS","year":2010,"question":"The Nisab for silver is:","options":[\"595 grams\",\"200 grams\",\"500 grams\",\"1000 grams\"],"correctIndex":0,"explanation":"595 grams of silver is the Nisab."},
{"subject":"IRS","year":2011,"question":"The rate of Zakat on money and gold is:","options":[\"2.5% (1/40)\",\"5%\",\"10%\",\"20%\"],"correctIndex":0,"explanation":"Zakat is 2.5% of wealth."},
{"subject":"IRS","year":2012,"question":"Zakat al-Fitr is given before:","options":[\"Eid al-Fitr prayer\",\"Ramadan\",\"Hajj\",\"Eid al-Adha\"],"correctIndex":0,"explanation":"Zakat al-Fitr is paid before the Eid prayer."},
{"subject":"IRS","year":2013,"question":"The amount of Zakat al-Fitr is:","options":[\"One sa\" of food\",\"One gold coin\",\"One silver coin\",\"2.5% of wealth\"],"correctIndex":0,"explanation":"It is typically one sa\" (approx 2.5-3 kg) of staple food."},
{"subject":"IRS","year":2014,"question":"Fasting (Sawm) in Ramadan is obligatory on:","options":[\"Every sane, adult Muslim\",\"Children\",\"The sick\",\"The elderly\"],"correctIndex":0,"explanation":"Fasting is obligatory on all sane, adult Muslims who are able."},
{"subject":"IRS","year":2015,"question":"Who is exempted from fasting in Ramadan?","options":[\"The sick, travelers, menstruating women, and the aged\",\"Only children\",\"Only the sick\",\"Only travelers\"],"correctIndex":0,"explanation":"These groups are exempted and must make up or pay."},
{"subject":"IRS","year":2016,"question":"The month of Ramadan is the month in which:","options":[\"The Quran was revealed\",\"The Prophet was born\",\"The Hijra began\",\"The Ka\"bah was built\"],"correctIndex":0,"explanation":"The Quran was revealed in Ramadan."},
{"subject":"IRS","year":2017,"question":"The Night of Decree (Laylat al-Qadr) is better than:","options":[\"1000 months\",\"1 year\",\"100 years\",\"10 years\"],"correctIndex":0,"explanation":"Laylat al-Qadr is worth more than 1000 months."},
{"subject":"IRS","year":2018,"question":"Laylat al-Qadr is found in the last:","options":[\"10 nights of Ramadan\",\"7 nights\",\"5 nights\",\"3 nights\"],"correctIndex":0,"explanation":"It is sought in the last 10 nights."},
{"subject":"IRS","year":2019,"question":"Hajj is obligatory on every Muslim who is:","options":[\"Physically and financially able\",\"Able to walk\",\"Wealthy only\",\"Healthy only\"],"correctIndex":0,"explanation":"Hajj is required for those with the means and ability."},
{"subject":"IRS","year":2020,"question":"Hajj is performed in the month of:","options":[\"Dhul-Hijjah\",\"Ramadan\",\"Muharram\",\"Rajab\"],"correctIndex":0,"explanation":"Hajj occurs in the month of Dhul-Hijjah."},
{"subject":"IRS","year":2021,"question":"The most important ritual of Hajj is:","options":[\"Standing at Arafat\",\"Tawaf\",\"Sa\"i\",\"Stoning the Jamarat\"],"correctIndex":0,"explanation":"Wuquf at Arafat is the central rite."},
{"subject":"IRS","year":2022,"question":"The Hajj is also known as:","options":[\"The fifth pillar\",\"The fourth pillar\",\"The second pillar\",\"The third pillar\"],"correctIndex":0,"explanation":"Hajj is the fifth pillar of Islam."},
{"subject":"IRS","year":2023,"question":"Umrah is often called the:","options":[\"Minor pilgrimage\",\"Major pilgrimage\",\"Fifth pillar\",\"Mandatory pilgrimage\"],"correctIndex":0,"explanation":"Umrah is the minor pilgrimage."},
{"subject":"IRS","year":2024,"question":"The Ka\"bah is located in:","options":[\"Mecca\",\"Medina\",\"Jerusalem\",\"Najd\"],"correctIndex":0,"explanation":"The Ka\"bah is in Mecca."},
{"subject":"IRS","year":2025,"question":"The Black Stone (Al-Hajar al-Aswad) is:","options":[\"Set in the eastern corner of the Ka\"bah\",\"Set in the western corner\",\"Set in the northern corner\",\"Set in the southern corner\"],"correctIndex":0,"explanation":"The Black Stone is in the eastern corner."},
{"subject":"IRS","year":2026,"question":"The three types of Hajj are:","options":[\"Ifrad, Qiran, Tamattu\"\",\"Ifrad, Qiran, Tawaf\",\"Tamattu, Tawaf, Qiran\",\"Sai, Tawaf, Wuquf\"],"correctIndex":0,"explanation":"These are the three forms of Hajj."},

// ============================================================
// SECTION 4: Tawhid, Aqidah & Islamic Theology (Q421–Q530)
// ============================================================
{"subject":"IRS","year":2000,"question":"The term \"Tawhid\" means:","options":[\"Oneness of God\",\"Prophethood\",\"Judgment Day\",\"Angels\"],"correctIndex":0,"explanation":"Tawhid is the belief in the absolute oneness of Allah."},
{"subject":"IRS","year":2001,"question":"The opposite of Tawhid is:","options":[\"Shirk (associating partners with Allah)\",\"Kufr\",\"Nifaq\",\"Fisq\"],"correctIndex":0,"explanation":"Shirk is the gravest sin in Islam."},
{"subject":"IRS","year":2002,"question":"The concept of \"Tawhid al-Rububiyyah\" refers to:","options":[\"Belief that Allah is the sole Creator and Sustainer\",\"Belief in the oneness of worship\",\"Belief in Allah\"s names and attributes\",\"Belief in the Prophets\"],"correctIndex":0,"explanation":"Rububiyyah is lordship – Allah as the sole Creator and Sustainer."},
{"subject":"IRS","year":2003,"question":"The concept of \"Tawhid al-Uluhiyyah\" refers to:","options":[\"Belief that Allah alone is worthy of worship\",\"Belief in Allah\"s lordship\",\"Belief in Allah\"s names and attributes\",\"Belief in the Prophets\"],"correctIndex":0,"explanation":"Uluhiyyah is the oneness of worship."},
{"subject":"IRS","year":2004,"question":"The concept of \"Tawhid al-Asma wa al-Sifat\" refers to:","options":[\"Belief in Allah\"s names and attributes as revealed\",\"Belief in Allah\"s lordship\",\"Belief in Allah\"s worship\",\"Belief in the Prophets\"],"correctIndex":0,"explanation":"This is the third category of Tawhid."},
{"subject":"IRS","year":2005,"question":"The name \"Al-Quddus\" means:","options":[\"The Most Holy\",\"The Most Merciful\",\"The All-Knowing\",\"The All-Powerful\"],"correctIndex":0,"explanation":"Al-Quddus is the Most Holy."},
{"subject":"IRS","year":2006,"question":"The name \"Al-Ahad\" means:","options":[\"The One\",\"The Absolute\",\"The Eternal\",\"The Unique\"],"correctIndex":0,"explanation":"Al-Ahad means the One."},
{"subject":"IRS","year":2007,"question":"The name \"Al-Samad\" means:","options":[\"The Eternal, Self-Sufficient\",\"The All-Hearing\",\"The All-Seeing\",\"The Most Great\"],"correctIndex":0,"explanation":"Al-Samad is the Eternal and Self-Sufficient."},
{"subject":"IRS","year":2008,"question":"The angels are created from:","options":[\"Light\",\"Fire\",\"Clay\",\"Water\"],"correctIndex":0,"explanation":"Angels are created from light (nur)."},
{"subject":"IRS","year":2009,"question":"Jinn are created from:","options":[\"Smokeless fire\",\"Clay\",\"Water\",\"Light\"],"correctIndex":0,"explanation":"Jinn are created from smokeless fire."},
{"subject":"IRS","year":2010,"question":"The first creature created by Allah was:","options":[\"The Pen (Al-Qalam)\",\"The Throne\",\"Angels\",\"Adam\"],"correctIndex":0,"explanation":"The Pen was the first creation."},
{"subject":"IRS","year":2011,"question":"The Day of Judgment is known in Arabic as:","options":[\"Yawm al-Qiyamah\",\"Yawm al-Jum\"ah\",\"Yawm al-Arafah\",\"Yawm al-Nahr\"],"correctIndex":0,"explanation":"Yawm al-Qiyamah is the Day of Resurrection."},
{"subject":"IRS","year":2012,"question":"The signs of the Day of Judgment include:","options":[\"The appearance of Dajjal, Ya\"juj and Ma\"juj, the Beast\",\"The sun rising from the West\",\"The smoke\",\"All of these\"],"correctIndex":3,"explanation":"All are major signs."},
{"subject":"IRS","year":2013,"question":"The Angel of Death is:","options":[\"Malak al-Mawt (Azrael)\",\"Jibreel\",\"Mika\"il\",\"Israfil\"],"correctIndex":0,"explanation":"Azrael is the Angel of Death."},
{"subject":"IRS","year":2014,"question":"The Angel who is responsible for revelation is:","options":[\"Jibreel (Gabriel)\",\"Mika\"il (Michael)\",\"Israfil\",\"Malak al-Mawt\"],"correctIndex":0,"explanation":"Jibreel brought the revelation."},
{"subject":"IRS","year":2015,"question":"The Angel responsible for blowing the Trumpet is:","options":[\"Israfil\",\"Jibreel\",\"Mika\"il\",\"Ridwan\"],"correctIndex":0,"explanation":"Israfil will blow the Trumpet."},
{"subject":"IRS","year":2016,"question":"The Angel responsible for rain and sustenance is:","options":[\"Mika\"il\",\"Jibreel\",\"Israfil\",\"Malak al-Mawt\"],"correctIndex":0,"explanation":"Mika\"il is responsible for provisions."},
{"subject":"IRS","year":2017,"question":"The concept of \"Qadar\" in Islam means:","options":[\"Divine predestination and decree\",\"Free will\",\"Human choice\",\"Fate only\"],"correctIndex":0,"explanation":"Qadar is Allah\"s complete knowledge and decree."},
{"subject":"IRS","year":2018,"question":"Belief in Qadar is one of the pillars of:","options":[\"Iman (faith)\",\"Islam\",\"Ihsan\",\"Tawhid\"],"correctIndex":0,"explanation":"It is the sixth pillar of iman."},
{"subject":"IRS","year":2019,"question":"The six pillars of Iman are:","options":[\"Belief in Allah, angels, books, messengers, the Last Day, and divine decree\",\"Belief in Allah, angels, books, messengers, jihad, and divine decree\",\"Belief in Allah, angels, books, prophets, imams, and divine decree\",\"Belief in Allah, angels, books, prophets, the Last Day, and paradise\"],"correctIndex":0,"explanation":"These are the six articles of faith."},
{"subject":"IRS","year":2020,"question":"The Four Rightly Guided Caliphs are:","options":[\"Abu Bakr, Umar, Uthman, Ali\",\"Abu Bakr, Umar, Uthman, Mu\"awiyah\",\"Abu Bakr, Umar, Uthman, Abu Ubaidah\",\"Abu Bakr, Umar, Uthman, Talha\"],"correctIndex":0,"explanation":"These are the Rashidun Caliphs."},
{"subject":"IRS","year":2021,"question":"The first caliph after the Prophet was:","options":[\"Abu Bakr as-Siddiq\",\"Umar ibn al-Khattab\",\"Uthman ibn Affan\",\"Ali ibn Abi Talib\"],"correctIndex":0,"explanation":"Abu Bakr was elected as the first caliph."},
{"subject":"IRS","year":2022,"question":"The second caliph was:","options":[\"Umar ibn al-Khattab\",\"Abu Bakr\",\"Uthman\",\"Ali\"],"correctIndex":0,"explanation":"Umar succeeded Abu Bakr."},
{"subject":"IRS","year":2023,"question":"The third caliph was:","options":[\"Uthman ibn Affan\",\"Umar\",\"Ali\",\"Abu Bakr\"],"correctIndex":0,"explanation":"Uthman was the third caliph."},
{"subject":"IRS","year":2024,"question":"The fourth caliph was:","options":[\"Ali ibn Abi Talib\",\"Uthman\",\"Umar\",\"Abu Bakr\"],"correctIndex":0,"explanation":"Ali was the fourth caliph."},
